import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI } from "@google/genai";
import "dotenv/config";
import multer from "multer";
import FormData from "form-data";
import fetch from "node-fetch";

async function startServer() {
  console.log("Starting MedNote server...");
  const app = express();
  const PORT = 3000;

  const upload = multer({ storage: multer.memoryStorage() });

  // Health check endpoint
  app.get("/api/health", (req, res) => {
    res.json({ status: "ok", timestamp: new Date().toISOString() });
  });

  // DocEngine health check
  app.get("/api/docengine-health", async (req, res) => {
    console.log("=== [DOCENGINE] RECEBIDA REQUISIĂĂO DE SAĂDE DA IA [GET /api/docengine-health] ===");
    console.log(`- process.env.DOCENGINE_API_KEY: ${process.env.DOCENGINE_API_KEY ? "Configurada (tamanho: " + process.env.DOCENGINE_API_KEY.length + ")" : "NĂŁo configurada"}`);
    console.log(`- process.env.DOCENGINE_API_URL: ${process.env.DOCENGINE_API_URL || "NĂŁo configurada"}`);

    try {
      let apiKey = process.env.DOCENGINE_API_KEY || "dk_app_398621514c374c1bbaee5c20d65f2a83";
      let baseUrl = (process.env.DOCENGINE_API_URL || "https://drive-ai-file-reader-572028997371.us-east1.run.app").trim().replace(/\/$/, '');

      // ResiliĂȘncia de URL: ForĂ§ar atualizaĂ§ĂŁo se contiver o host antigo
      if (baseUrl.includes("spherical-leaf")) {
        console.warn("â ïž URL antiga detectada em process.env.DOCENGINE_API_URL. ForĂ§ando redirecionamento para o ambiente novo.");
        baseUrl = "https://drive-ai-file-reader-572028997371.us-east1.run.app";
      }

      console.log(`- URL base de destino calculada: ${baseUrl}`);
      console.log(`- API Key integrada: ${apiKey.substring(0, 10)}...`);

      const tryHealth = async (key: string, url: string) => {
        console.log(`- Efetuando fetch na URL de saĂșde: ${url}`);
        return fetch(url, {
          method: 'GET',
          headers: {
            'x-api-key': key,
            'Content-Type': 'application/json'
          }
        });
      };

      // Tenta a chave principal com /api/health
      let response = await tryHealth(apiKey, `${baseUrl}/api/health`);

      // Se retornar 404, tenta na raiz /health ou base
      if (response.status === 404) {
        console.log("â ïž /api/health retornou 404, tentando fallback para /health...");
        response = await tryHealth(apiKey, `${baseUrl}/health`);
      }

      // Se ainda falhar com o status, ou se a chave falhar, tenta com a chave alternativa
      if (!response.ok) {
        console.warn(`â ïž Chamada inicial de saĂșde retornou status ${response.status}. Tentando chave alternativa...`);
        const altKey = "dk_app_9afda75222e940538b598d9564b693b8";
        response = await tryHealth(altKey, `${baseUrl}/api/health`);
        if (response.status === 404) {
          response = await tryHealth(altKey, `${baseUrl}/health`);
        }
      }

      if (!response.ok) {
        throw new Error(`Erro retornado pela DocEngine: ${response.status} ${response.statusText}`);
      }

      const data = await response.json();
      console.log("â ConexĂŁo estabelecida com a IA de forma bem sucedida!", JSON.stringify(data));
      res.json(data);
    } catch (error: any) {
      console.error('â Erro no teste de integridade da DocEngine:', error.message);
      res.status(500).json({ error: error.message });
    }
  });

  // DocEngine API integration
  app.post("/api/read", upload.single('file'), async (req, res) => {
    console.log("=== [DOCENGINE] RECEBIDA REQUISIĂĂO DE EXTRAĂĂO DE DOCUMENTO [POST /api/read] ===");
    try {
      const file = req.file;
      if (!file) {
        console.error("â Nenhum arquivo enviado no corpo da requisiĂ§ĂŁo.");
        return res.status(400).json({ error: "Nenhum arquivo enviado." });
      }

      let apiKey = process.env.DOCENGINE_API_KEY || "dk_app_398621514c374c1bbaee5c20d65f2a83";
      let baseUrl = (process.env.DOCENGINE_API_URL || "https://drive-ai-file-reader-572028997371.us-east1.run.app").trim().replace(/\/$/, '');

      if (baseUrl.includes("spherical-leaf")) {
        console.warn("â ïž URL antiga detectada em process.env.DOCENGINE_API_URL. ForĂ§ando redirecionamento para o ambiente novo.");
        baseUrl = "https://drive-ai-file-reader-572028997371.us-east1.run.app";
      }

      const apiUrl = baseUrl + "/api/read";
      console.log(`- Enviando arquivo '${file.originalname}' (${file.size} bytes) para: ${apiUrl}`);

      const performRead = async (key: string) => {
        const form = new FormData();
        form.append('file', file.buffer, {
          filename: file.originalname,
          contentType: file.mimetype,
        });

        return fetch(apiUrl, {
          method: 'POST',
          headers: {
            'x-api-key': key,
            ...form.getHeaders()
          },
          body: form
        });
      };

      let response = await performRead(apiKey);

      if (!response.ok) {
        console.warn(`â ïž Chamada inicial para /api/read falhou (status ${response.status}). Tentando com a chave alternativa de fallback...`);
        const altKey = "dk_app_9afda75222e940538b598d9564b693b8";
        response = await performRead(altKey);
      }

      if (!response.ok) {
        const errorText = await response.text();
        console.error('â Erro no retorno da extraĂ§ĂŁo pela DocEngine:', errorText);
        throw new Error(`Erro na DocEngine: ${response.status} ${response.statusText}`);
      }

      const data = (await response.json()) as any;
      console.log("â Leitura e extraĂ§ĂŁo estruturada do documento efetuada com sucesso!");
      res.json(data.analysis || data);
    } catch (error: any) {
      console.error('â Erro na extraĂ§ĂŁo de documento via DocEngine:', error);
      res.status(500).json({ error: error.message || 'Erro ao processar com DocEngine.' });
    }
  });

  // DocEngine API integration (reconcile)
  app.post("/api/reconcile", upload.single('file'), async (req, res) => {
    console.log("=== [DOCENGINE] RECEBIDA REQUISIĂĂO DE RECONCILIAĂĂO DE PAGAMENTOS [POST /api/reconcile] ===");
    try {
      const file = req.file;
      if (!file) {
        console.error("â Nenhum arquivo enviado no corpo da requisiĂ§ĂŁo.");
        return res.status(400).json({ error: "Nenhum arquivo enviado." });
      }

      let apiKey = process.env.DOCENGINE_API_KEY || "dk_app_398621514c374c1bbaee5c20d65f2a83";
      let baseUrl = (process.env.DOCENGINE_API_URL || "https://drive-ai-file-reader-572028997371.us-east1.run.app").trim().replace(/\/$/, '');

      if (baseUrl.includes("spherical-leaf")) {
        console.warn("â ïž URL antiga detectada em process.env.DOCENGINE_API_URL. ForĂ§ando redirecionamento para o ambiente novo.");
        baseUrl = "https://drive-ai-file-reader-572028997371.us-east1.run.app";
      }

      const apiUrl = baseUrl + "/api/reconcile";
      console.log(`- Enviando relatĂłrio '${file.originalname}' (${file.size} bytes) para: ${apiUrl}`);

      const performRead = async (key: string) => {
        const form = new FormData();
        form.append('file', file.buffer, {
          filename: file.originalname,
          contentType: file.mimetype,
        });

        return fetch(apiUrl, {
          method: 'POST',
          headers: {
            'x-api-key': key,
            ...form.getHeaders()
          },
          body: form
        });
      };

      let response = await performRead(apiKey);

      if (!response.ok) {
        console.warn(`â ïž Chamada inicial para /api/reconcile falhou (status ${response.status}). Tentando com a chave alternativa de fallback...`);
        const altKey = "dk_app_9afda75222e940538b598d9564b693b8";
        response = await performRead(altKey);
      }

      if (!response.ok) {
        const errorText = await response.text();
        console.error('â Erro no retorno da conciliaĂ§ĂŁo pela DocEngine:', errorText);
        throw new Error(`Erro na DocEngine: ${response.status} ${response.statusText}`);
      }

      const data = (await response.json()) as any;
      console.log("â ConciliaĂ§ĂŁo de pagamentos extraĂ­da com sucesso!");
      res.json(data.analysis || data);
    } catch (error: any) {
      console.error('â Erro no fechamento de reconciliaĂ§ĂŁo via DocEngine:', error);
      res.status(500).json({ error: error.message || 'Erro ao processar com DocEngine.' });
    }
  });

  // Set higher limit for large PDF base64 payloads
  app.use(express.json({ limit: '50mb' }));

  // API Routes
  app.post("/api/gemini/extract", async (req, res) => {
    try {
      const { fileType, base64Data, prompt, schema } = req.body;

      const apiKey = process.env.GEMINI_API_KEY;
      if (!apiKey) {
        return res.status(400).json({ error: "Chave de API Gemini n\u00e3o configurada. Configure no painel de segredos." });
      }

      const ai = new GoogleGenAI({ 
        apiKey,
        httpOptions: { headers: { 'User-Agent': 'aistudio-build' } }
      });

      const modelsToTry = ['gemini-3.5-flash', 'gemini-3.1-flash-lite', 'gemini-3.1-pro-preview'];
      let response: any = null;
      let lastError: any = null;

      for (const model of modelsToTry) {
        try {
          response = await ai.models.generateContent({
            model,
            contents: [
              {
                role: 'user',
                parts: [
                  { text: prompt },
                  {
                    inlineData: {
                      data: base64Data,
                      mimeType: fileType,
                    },
                  },
                ],
              },
            ],
            config: {
              responseMimeType: 'application/json',
              responseSchema: schema,
              temperature: 0.1,
            },
          });
          break; // Sucesso, nĂŁo precisa tentar outro modelo
        } catch (error: any) {
          console.warn(`Erro com o modelo ${model}:`, error.message);
          lastError = error;

          const errorMsg = error.message?.toLowerCase() || '';
          const isRetryable = errorMsg.includes('429') || 
                             errorMsg.includes('quota') || 
                             errorMsg.includes('resource_exhausted') ||
                             errorMsg.includes('503') ||
                             errorMsg.includes('unavailable') ||
                             errorMsg.includes('demand') ||
                             errorMsg.includes('404') ||
                             errorMsg.includes('not found') ||
                             errorMsg.includes('not supported');

          if (!isRetryable) {
            throw error; // Se o erro nĂŁo for de limite, indisponibilidade ou modelo nĂŁo encontrado, para aqui
          }
        }
      }

      if (!response && lastError) {
        throw lastError;
      }

      if (!response.text) {
        throw new Error("N\u00e3o foi poss\u00edvel extrair dados da imagem/documento.");
      }

      const result = JSON.parse(response.text);
      res.json(result);
    } catch (error: any) {
      console.error('Gemini error:', error);
      res.status(500).json({ error: error.message || 'Erro ao processar documento.' });
    }
  });

  // Vite middleware for development
  if (process.env.NODE_ENV !== "production") {
    console.log("Initializing Vite in development mode...");
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
    console.log("Vite middleware attached.");
  } else {
    // In production, the server is bundled into dist/server.cjs
    // So __dirname will be the dist directory itself
    const distPath = typeof __dirname !== 'undefined' 
      ? __dirname 
      : path.join(process.cwd(), 'dist');

    console.log(`Serving static files from: ${distPath}`);

    app.use(express.static(distPath));

    // Support SPA routing - serve index.html for any unknown routes
    app.get('*', (req, res) => {
      const indexPath = path.join(distPath, 'index.html');
      res.sendFile(indexPath);
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server fully started and listening on http://0.0.0.0:${PORT}`);
  });
}

startServer();

