import React, { useState } from 'react';
import { useApp, ElectiveSurgery } from '../store/AppContext';
import { PageHeader } from '../components/PageHeader';
import { Dialog } from '../components/ui/Dialog';
import { Plus, Search, Check, Edit2, Trash2, Info } from 'lucide-react';
import { format, parseISO } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { cn, formatCurrency } from '../lib/utils';
import { toast } from 'sonner';

export function ElectiveSurgeries() {
  const { data, addElectiveSurgery, updateElectiveSurgery, deleteElectiveSurgery, addSurgery } = useApp();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [hospitalFilter, setHospitalFilter] = useState('ALL');
  const [draftSurgery, setDraftSurgery] = useState<any>(null);
  const [isFinishingSurgery, setIsFinishingSurgery] = useState(false);
  const [surgeryToDelete, setSurgeryToDelete] = useState<any>(null);

  const handleSaveDraft = (e: React.FormEvent) => {
    e.preventDefault();
    if (!draftSurgery) return;
    const form = e.target as HTMLFormElement;
    const date = (form.elements.namedItem('date') as HTMLInputElement).value;
    const patientName = (form.elements.namedItem('patientName') as HTMLInputElement).value;
    const procedure = (form.elements.namedItem('procedure') as HTMLInputElement).value;
    const hospitalId = (form.elements.namedItem('hospitalId') as HTMLSelectElement).value;
    const isParticular = (form.elements.namedItem('isParticular') as HTMLInputElement).checked;
    const particularValue = parseFloat((form.elements.namedItem('particularValue') as HTMLInputElement)?.value || '0');

    if (isFinishingSurgery) {
       // Convert to regular surgery
       const insurance = isParticular ? 'PARTICULAR' : (form.elements.namedItem('insurance') as HTMLInputElement).value;
       const attendance = (form.elements.namedItem('attendance') as HTMLInputElement).value;
       const company = (form.elements.namedItem('company') as HTMLInputElement).value;
       const feesPaid = isParticular ? particularValue : parseFloat((form.elements.namedItem('feesPaid') as HTMLInputElement).value || '0');
       const receivedAmount = isParticular ? particularValue : parseFloat((form.elements.namedItem('receivedAmount') as HTMLInputElement).value || '0');

       addSurgery({ 
         date, 
         patientName, 
         insurance, 
         attendance, 
         procedure, 
         indication: procedure,
         company, 
         feesPaid, 
         receivedAmount, 
         hospitalId, 
         notes: '',
         isParticular,
         particularValue,
         photos: []
       });
       if (draftSurgery.id) deleteElectiveSurgery(draftSurgery.id);
       toast.success("Cirurgia registrada e movida para Cirurgias Realizadas!");
    } else {
       if (draftSurgery.id) {
         updateElectiveSurgery(draftSurgery.id, { date, patientName, procedure, hospitalId, isParticular, particularValue });
         toast.success("Procedimento atualizado!");
       } else {
         addElectiveSurgery({ date, patientName, procedure, hospitalId, isParticular, particularValue });
         toast.success("Procedimento solicitado com sucesso!");
       }
    }
    setDraftSurgery(null);
    setIsModalOpen(false);
    setIsFinishingSurgery(false);
  };

  const filteredSurgeries = (data.electiveSurgeries || []).filter(s => {
    // Search term filter
    const searchString = `${s.patientName} ${s.procedure} ${data.hospitals?.find(h => h.id === s.hospitalId)?.name || ''}`.toLowerCase();
    const matchesSearch = searchString.includes(searchTerm.toLowerCase());

    // Hospital filter
    const matchesHospital = hospitalFilter === 'ALL' || s.hospitalId === hospitalFilter;

    return matchesSearch && matchesHospital;
  }).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  return (
    <div className="flex flex-col min-h-full bg-zinc-50/50">
      <PageHeader 
        breadcrumbs={[
          { label: 'Eletivas Solicitadas' }
        ]}
      >
        <div className="flex items-center flex-wrap gap-2">
          <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar">
            <button 
              onClick={() => { setSearchTerm(''); setIsModalOpen(true); setIsFinishingSurgery(false); setDraftSurgery({ date: new Date().toISOString().split('T')[0] }); }} 
              className="flex items-center gap-2 bg-[#162744] text-white px-5 md:px-6 py-2 rounded-xl text-[9px] font-black uppercase tracking-tight transition-all shadow-md hover:shadow-lg active:scale-95"
            >
              <span className="action-dot" />
              <span>Nova Eletiva</span>
            </button>
          </div>
        </div>
      </PageHeader>

      <main className="flex-1 p-4 md:p-8 space-y-6 max-w-5xl mx-auto w-full">
        <div className="bg-[#162744] p-8 rounded-3xl shadow-xl shadow-zinc-200 text-center flex flex-col items-center justify-center border border-white/10 group">
          <div className="text-[9px] font-black text-zinc-400 uppercase tracking-[0.2em] mb-1 group-hover:text-zinc-300 transition-colors">Procedimentos Aguardando</div>
          <div className="text-4xl font-bold text-white tabular-nums tracking-tighter uppercase">{data.electiveSurgeries?.length || 0} Pacientes</div>
        </div>

        <div className="bg-white rounded-3xl border border-zinc-200 shadow-sm overflow-hidden flex flex-col min-h-[400px]">
          <div className="px-6 py-4 border-b border-zinc-50 flex flex-col md:flex-row gap-4 items-center">
             <div className="relative flex-1 w-full">
                <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-zinc-300" />
                <input 
                  type="text" 
                  placeholder="BUSCAR POR NOME OU PROCEDIMENTO..." 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)} 
                  className="text-[10px] font-black uppercase tracking-widest w-full pl-9 pr-4 py-2.5 bg-zinc-50 border border-zinc-100 rounded-xl focus:outline-none focus:border-zinc-200 transition-all" 
                />
             </div>

             <select
                value={hospitalFilter}
                onChange={(e) => setHospitalFilter(e.target.value)}
                className="text-[10px] font-black uppercase tracking-widest w-full md:w-auto px-4 py-2.5 bg-zinc-50 border border-zinc-100 rounded-xl focus:outline-none focus:border-zinc-200 transition-all"
             >
                <option value="ALL">TODOS OS HOSPITAIS</option>
                {data.hospitals.map(h => (
                  <option key={h.id} value={h.id}>{h.name}</option>
                ))}
             </select>
          </div>

          <div className="overflow-x-auto flex-1 w-full">
            <table className="w-full text-left min-w-max md:min-w-full">
               <thead className="bg-zinc-50/50 text-[9px] text-zinc-400 uppercase font-black tracking-[0.2em] border-b border-zinc-100">
                  <tr>
                     <th className="px-6 py-4">Data da SolicitaĂ§ĂŁo</th>
                     <th className="px-6 py-4">Paciente</th>
                     <th className="px-6 py-4">Hospital</th>
                     <th className="px-6 py-4">IndicaĂ§ĂŁo</th>
                     <th className="px-6 py-4 text-right">AĂ§Ă”es</th>
                  </tr>
               </thead>
               <tbody className="divide-y divide-zinc-50">
                 {filteredSurgeries.length === 0 ? (
                    <tr>
                       <td colSpan={5} className="px-6 py-12 text-center text-zinc-400">
                          <div className="flex flex-col items-center gap-2">
                             <div className="w-12 h-12 bg-zinc-50 rounded-2xl flex items-center justify-center mb-2">
                                <Plus className="w-5 h-5 text-zinc-300" />
                             </div>
                             <p className="text-xs font-bold uppercase tracking-widest">Nenhuma eletiva encontrada</p>
                          </div>
                       </td>
                    </tr>
                 ) : (
                    filteredSurgeries.map((surgery) => {
                       const hosp = data.hospitals?.find(h => h.id === surgery.hospitalId);
                       return (
                          <tr key={surgery.id} className="group hover:bg-zinc-50/80 transition-colors">
                             <td className="px-4 md:px-6 py-4">
                                <div className="text-[11px] font-mono font-bold text-zinc-800">{format(parseISO(surgery.date), 'dd/MM/yyyy')}</div>
                             </td>
                             <td className="px-4 py-4 text-[11px] font-bold text-zinc-900 uppercase">
                                <div className="flex flex-col">
                                   <div className="max-w-[150px] md:max-w-[200px] truncate" title={surgery.patientName}>{surgery.patientName}</div>
                                   {surgery.isParticular && (
                                      <div className="flex items-center gap-1 mt-0.5">
                                         <div className="px-1.5 py-0.5 bg-emerald-50 text-emerald-600 rounded text-[7px] font-black uppercase tracking-tighter border border-emerald-100">Particular</div>
                                         <span className="text-[9px] font-mono font-bold text-emerald-600">{formatCurrency(surgery.particularValue || 0)}</span>
                                      </div>
                                   )}
                                </div>
                             </td>
                             <td className="px-4 py-4 text-[10px] font-black text-zinc-500 uppercase tracking-tight">
                                <div className="max-w-[120px] md:max-w-[150px] truncate" title={hosp?.name || '---'}>{hosp?.name || '---'}</div>
                             </td>
                             <td className="px-4 py-4 text-[10px] font-bold text-zinc-500 uppercase">
                                <div className="max-w-[150px] md:max-w-[200px] truncate" title={surgery.procedure}>{surgery.procedure}</div>
                             </td>
                             <td className="px-4 md:px-6 py-4 text-right">
                                <div className="flex justify-end gap-2 transition-opacity">
                                   <button 
                                     onClick={() => { setDraftSurgery(surgery); setIsFinishingSurgery(true); setIsModalOpen(true); }}
                                     className="px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-lg text-[9px] font-black uppercase flex items-center gap-1 hover:bg-emerald-100 transition-colors"
                                     title="Marcar como realizada (migrar p/ Cirurgias)"
                                   >
                                     <Check className="w-3 h-3" /> Realizada
                                   </button>
                                   <button 
