import React from 'react';
import { useApp } from '../store/AppContext';
import { Logo } from '../components/Logo';
import { LogIn, ShieldCheck, Cloud, Zap, Eye, EyeOff, Mail, Lock, Loader2, ExternalLink } from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';

export function LoginPage() {
  const { signIn } = useApp();
  const [isLoading, setIsLoading] = React.useState(false);
  const [error, setError] = React.useState<string | null>(null);

  const handleGoogleSignIn = async () => {
    setIsLoading(true);
    setError(null);
    try {
      await signIn();
    } catch (err) {
      setError('Erro ao entrar com Google.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-slate-100 via-slate-50 to-white font-sans text-zinc-900">
      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, ease: "easeOut" }}
        className="w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/50 border border-slate-100 p-10 flex flex-col items-center space-y-8"
      >
        <Logo className="h-16" />

        <div className="space-y-1 text-center">
          <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">MedNotes Cloud</h1>
          <p className="text-slate-400 text-[10px] font-bold uppercase tracking-[0.2em] leading-none">GestĂŁo Especializada</p>
        </div>

        {error && (
          <p className="text-[10px] font-bold text-red-500 uppercase tracking-wider text-center">{error}</p>
        )}

        <div className="w-full space-y-4">
          <button 
            onClick={handleGoogleSignIn}
            disabled={isLoading}
            className="w-full bg-white border-2 border-slate-100 py-3 rounded-2xl flex items-center justify-center gap-3 hover:border-slate-300 transition-all text-[9px] font-black uppercase tracking-widest"
          >
            {isLoading ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <img src="https://www.google.com/favicon.ico" className="w-4 h-4 grayscale opacity-50 group-hover:grayscale-0 group-hover:opacity-100 transition-all" alt="Google" />
            )}
            Entrar com Google
          </button>

          {window.self !== window.top && (
            <div className="flex justify-center mt-4">
              <a
                href={window.location.href}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center gap-1 text-[9px] font-black uppercase tracking-widest text-slate-400 hover:text-slate-900 transition-colors"
              >
                <ExternalLink className="w-3 h-3" />
                Abrir Fora
              </a>
            </div>
          )}
        </div>

        <div className="pt-4 flex flex-col items-center">
          <p className="text-[8px] text-slate-300 font-bold uppercase tracking-[0.2em]">
            Uso Profissional Restrito
          </p>
        </div>
      </motion.div>
    </div>
  );
}

