                    <div className="p-3 bg-white/10 rounded-full">
                      {syncStatus === 'syncing' ? (
                        <RefreshCw className="w-5 h-5 text-blue-400 animate-spin" />
                      ) : syncStatus === 'error' ? (
                        <CloudOff className="w-5 h-5 text-red-400" />
                      ) : (
                        <Cloud className="w-5 h-5 text-emerald-400" />
                      )}
                    </div>
                    <div>
                      <p className="text-[10px] font-black text-white uppercase tracking-widest">
                        Status: {syncStatus === 'syncing' ? 'Sincronizando...' : syncStatus === 'error' ? 'Erro na Ășltima tentativa' : 'Sincronizado'}
                      </p>
                      <p className="text-[9px] text-zinc-500 font-bold uppercase tracking-tight">
                        {lastSynced ? `Ăltimo envio para Google Drive: ${new Date(lastSynced).toLocaleString('pt-BR')}` : 'Aguardando primeiro envio...'}
                      </p>
                    </div>
                  </div>
                  <button
                    onClick={() => syncDataToDrive(true)}
                    disabled={syncStatus === 'syncing'}
                    className="p-3 hover:bg-white/10 rounded-xl transition-all"
                    title="Sincronizar agora"
