        ? 'A extraĂ§ĂŁo do PDF falhou. Certifique-se de que o documento Ă© legĂ­vel.'
        : 'A leitura falhou. Tente tirar uma foto mais aproximada e nĂ­tida da etiqueta.';

      if (err instanceof Error && err.message) {
        msg = err.message;
      }

      setErrorMessage(msg);
