    }
  }, [accessToken]);

  useEffect(() => {
    localStorage.setItem('cloud_backup_enabled', String(cloudBackupEnabled));
  }, [cloudBackupEnabled]);

  useEffect(() => {
    if (lastSynced) {
      localStorage.setItem('last_synced', lastSynced);
    }
  }, [lastSynced]);

  useEffect(() => {
