  const syncDataToDrive = async (forceManual = false) => {
    if (!user || !cloudBackupEnabled || isOffline) return;

    if (forceManual && !accessToken) {
      await signInWithGoogle();
      return;
    }

    if (!accessToken) return;

    setSyncStatus('syncing');

